sp_rectangle_menu_item.record_script:
var bannerAwaitingOUReassignment = function(data){
  var u = gs.getUser().getID();
  var filter = 'active=true^state=11^primary_assigneeISEMPTY';
  if(!gs.hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin")){
    filter += '^state=11^primary_assigneeISEMPTY^u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe^active=true'; 
  }

  var tbf = new TaskerBannerFilters();

  tbf.label = 'Awaiting OU Reassignment';
  tbf.table = 'x_153465_discovert_route_task_instance';
  tbf.filter = filter;
  tbf.orderDesc = 'sys_updated_on';
  tbf.idField = 'sys_id';
  tbf.displayFieldName = 'task_name';
  tbf.linkView = 'sp';
  tbf.pageId = 'discovertasker_taskdetails';
  tbf.viewAllLinkTitle = gs.getMessage('View all requests');
  tbf.viewAllLinkPageId = 'discovertasker_detailsdrilldown';
  tbf.viewAllLinkView = 'Unassigned';

  if(gs.hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin")){
    tbf.viewAllLinkFilter = 'stateIN11^primary_assigneeISEMPTY^active%3Dtrue';
  }else{
    tbf.viewAllLinkFilter = 'stateIN11^primary_assigneeISEMPTY^originator='+u+'^active%3Dtrue';

  }

  tbf.createBanner();
  data.items = tbf.items;
  data.record_watchers = tbf.record_watchers;
  data.count = tbf.count;

}

bannerAwaitingOUReassignment(data);
